export type HttpMethod = "GET" | "POST" | "PUT" | "DELETE";

export type ApiParameter = {
  name: string;
  type: string;
  required: boolean;
  description: string;
};

export type ApiExample = Record<string, unknown> | string | null;

export type ApiEndpoint = {
  slug: string;
  name: string;
  category: string;
  method: HttpMethod;
  endpoint: string;
  summary: string;
  description: string;
  parameters: ApiParameter[];
  requestExample: ApiExample;
  responseExample: ApiExample;
  tags: string[];
};

const categoryOrder = [
  "Commodity APIs",
  "Intelligence APIs",
  "Enrichment APIs",
  "Social APIs",
  "Advanced APIs",
  "Utility APIs",
  "Agent Kernel APIs",
  "Agent Utilities APIs",
  "Business Operations APIs",
] as const;

type EndpointSeed = Omit<ApiEndpoint, "slug" | "tags"> & { tags?: string[] };

function createEndpoint(config: EndpointSeed): ApiEndpoint {
  const slug = config.endpoint
    .replace(/^\//, "")
    .replace(/[{}]/g, "")
    .replace(/\//g, "-")
    .replace(/[^a-zA-Z0-9-]/g, "-")
    .replace(/-+/g, "-")
    .toLowerCase();

  return {
    ...config,
    slug,
    tags: config.tags ?? inferTags(config),
  };
}

function inferTags(config: Pick<ApiEndpoint, "category" | "endpoint" | "method">): string[] {
  return [config.category.replace(" APIs", ""), config.method, config.endpoint.split("/")[2] ?? "utility"];
}

